#!/bin/bash
# Safe cleanup script that checks which images are actually in use by Cloud Run
# Only deletes images that are NOT currently being used

PROJECT_ID="flashlive-daily-scraper"
REGION="us-central1"
KEEP_IMAGES=1  # Keep latest 1 image per service (services use SHA256 digests, so old images aren't needed)

echo "🔒 Safe Artifact Registry Image Cleanup"
echo "Project: $PROJECT_ID"
echo "This script will:"
echo "  1. Check which images are currently used by Cloud Run services"
echo "  2. Keep the latest $KEEP_IMAGES images per service"
echo "  3. Only delete images that are NOT in use"
echo ""

# Get list of images currently in use by Cloud Run services
echo "Checking which images are currently in use..."
IN_USE_IMAGES=$(gcloud run services list --project=$PROJECT_ID --region=$REGION --format="value(spec.template.spec.containers[0].image)" 2>&1 | grep -v "^$")

echo "Images currently in use by Cloud Run:"
echo "$IN_USE_IMAGES" | while read img; do
    if [ ! -z "$img" ]; then
        echo "  ✅ $img"
    fi
done

echo ""
echo "These images will NOT be deleted."
echo ""

# Function to check if an image is in use
is_image_in_use() {
    local image=$1
    echo "$IN_USE_IMAGES" | grep -q "$image"
    return $?
}

