    echo "📦 Repository: $repo"
    
    # Get all unique image packages
    local images=$(gcloud artifacts docker images list us-central1-docker.pkg.dev/$PROJECT_ID/$repo --limit=1000 --format="value(package)" 2>&1 | sed 's/@.*$//' | sort -u)
    
    if [ -z "$images" ]; then
        echo "  No images found"
        return
    fi
    
    local deleted_count=0
    local skipped_count=0
    
    # Process each unique image
    for image_base in $images; do
        echo ""
        echo "  Image: $image_base"
        
        # Get all versions, sorted by update_time (newest first)
        local all_versions=$(gcloud artifacts docker images list "$image_base" --limit=1000 --sort-by=~update_time --format="value(package)" 2>&1 | grep -v "^$")
        local total=$(echo "$all_versions" | wc -l)
        
        if [ $total -le $KEEP_IMAGES ]; then
            echo "    Total: $total | Keeping all (within limit)"
            continue
        fi
        
        # Get versions to keep (first KEEP_IMAGES)
        local keep=$(echo "$all_versions" | head -n $KEEP_IMAGES)
        # Get versions to potentially delete (rest)
        local to_delete=$(echo "$all_versions" | tail -n +$((KEEP_IMAGES + 1)) | grep -v "^$")
        
        local delete_count=$(echo "$to_delete" | wc -l)
        echo "    Total: $total | Keeping: $KEEP_IMAGES | Checking: $delete_count for deletion"
        
        # Delete old versions (only if not in use)
        for version in $to_delete; do
            if [ ! -z "$version" ]; then
                # Check if image is in use
                if is_image_in_use "$version"; then
                    echo "      ⚠️  SKIPPED (in use): $version"
                    ((skipped_count++))
                else
                    echo "      🗑️  Deleting: $version"
                    gcloud artifacts docker images delete "$version" --quiet --delete-tags 2>&1 > /dev/null
                    if [ $? -eq 0 ]; then
                        ((deleted_count++))
                    fi
                fi
            fi
        done
    done
    
    echo ""
    echo "  ✅ Deleted: $deleted_count | Skipped (in use): $skipped_count"
}

# Main execution
read -p "Continue with safe cleanup? (y/n) " -n 1 -r
echo ""
if [[ ! $REPLY =~ ^[Yy]$ ]]; then
    echo "Cancelled."
    exit 1
fi

# Process repositories
cleanup_repo_safe "cloud-run-source-deploy"
cleanup_repo_safe "gcf-artifacts"
cleanup_repo_safe "jobs"

echo ""
echo "✅ Safe cleanup complete!"
echo ""
echo "Checking updated storage..."
gcloud artifacts repositories describe gcr.io --project=$PROJECT_ID --location=us --format="get(name)" 2>&1 | head -1 | xargs -I {} gcloud artifacts repositories describe {} --project=$PROJECT_ID --location=us --format="get(Repository Size)" 2>&1
